using namespace std;

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    vector<long long> ans;
    for (auto& q : queries) {
        long long l = q[0], r = q[1], t = q[2];
        unordered_map<long long, long long> freq;
        for (long long i = l; i <= r; ++i) {
            freq[nums[i]]++;
        }
        long long best = -1;
        long long max_freq = 0;
        for (auto& [num, cnt] : freq) {
            if (cnt >= t) {
                if (cnt > max_freq) {
                    max_freq = cnt;
                    best = num;
                } else if (cnt == max_freq) {
                    if (num < best) {
                        best = num;
                    }
                }
            }
        }
        ans.push_back(best);
    }
    return ans;
}

