function solve(nums: number[], queries: number[][]): number[] {
    const ans: number[] = [];
    for (const q of queries) {
        const l = q[0], r = q[1], t = q[2];
        const freq = new Map<number, number>();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            freq.set(num, (freq.get(num) || 0) + 1);
        }
        let best = -1;
        let maxFreq = 0;
        for (const [num, cnt] of freq.entries()) {
            if (cnt >= t) {
                if (cnt > maxFreq) {
                    maxFreq = cnt;
                    best = num;
                } else if (cnt === maxFreq) {
                    if (num < best) {
                        best = num;
                    }
                }
            }
        }
        ans.push(best);
    }
    return ans;
}
```

