        long long best = -1;
        long long max_freq = 0;
        for (auto& [num, cnt] : freq) {
            if (cnt >= t) {
                if (cnt > max_freq) {
                    max_freq = cnt;
                    best = num;
                } else if (cnt == max_freq) {
                    if (num < best) {
                        best = num;
                    }
                }
            }
        }
        ans.push_back(best);
    }
    return ans;
}
